// Home Screen
const HomeScreen = () => {
  const navigation = useNavigation();
  const route = useRoute();

  useEffect(() => {
    if (route.params?.deepLinkError) {
      Alert.alert(
        'Navigation Error',
        `Could not navigate to "${route.params.originalScreen}". You have been redirected to Home.`
      );
    }
    if (route.params?.unknownRoute) {
      Alert.alert('Unknown Route', `The route "${route.params.unknownRoute}" is not recognized.`);
    }
  }, [route.params]);

  const testDeepLinks = [
    { label: 'Profile (User 123)', url: 'myapp://profile/123' },
    { label: 'Payment Confirm', url: 'myapp://payment/confirm' },
    { label: 'Payment with Transaction', url: 'myapp://payment/confirm/TXN456?amount=99.99' },
    { label: 'Campaign', url: 'myapp://campaign/SUMMER2024?source=email&discount=20' },
    { label: 'Notification', url: 'myapp://notification/N789/promo?title=Special+Offer' },
    { label: 'Settings', url: 'myapp://settings?theme=dark' },
  ];

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Deep Link Demo</Text>
      <Text style={styles.subtitle}>Test deep links by tapping below:</Text>

      {testDeepLinks.map((link, index) => (
        <TouchableOpacity
          key={index}
          style={styles.linkButton}
          onPress={() => Linking.openURL(link.url)}
        >
          <Text style={styles.linkButtonText}>{link.label}</Text>
          <Text style={styles.linkUrl}>{link.url}</Text>
        </TouchableOpacity>
      ))}

      <View style={styles.divider} />

      <Text style={styles.subtitle}>Direct Navigation:</Text>
      <View style={styles.navRow}>
        <TouchableOpacity
          style={styles.navButton}
          onPress={() => navigation.navigate('Profile', { userId: '456' })}
        >
          <Text style={styles.navButtonText}>Profile</Text>
        </TouchableOpacity>
        <TouchableOpacity
          style={styles.navButton}
          onPress={() => navigation.navigate('Payment', { action: 'confirm' })}
        >
          <Text style={styles.navButtonText}>Payment</Text>
        </TouchableOpacity>
        <TouchableOpacity
          style={styles.navButton}
          onPress={() => navigation.navigate('Settings')}
        >
          <Text style={styles.navButtonText}>Settings</Text>
        </TouchableOpacity>
      </View>
    </View>
  );
};

